SELECT AVG(h.income_range) AS average_income_range
FROM households h
WHERE h.contact_id = 'new_contact';

SELECT h.household_id, c.contact_id, c.first_name, c.last_name
FROM households h
JOIN contacts c ON h.contact_id = c.contact_id;

SELECT household_id, contacts_traced, household_members, engagement_score
FROM households
ORDER BY contacts_traced DESC, household_members DESC, engagement_score DESC;

SELECT *
FROM households
ORDER BY income_range ASC;

SELECT campaign_id, campaign_name, start_date, end_date, budget,
       status, target_audience, expected_reach, actual_reach, 
       conversion_rate
FROM campaigns
WHERE start_date = (
    SELECT MIN(start_date) FROM campaigns
) AND expected_reach = (
    SELECT MAX(expected_reach) FROM campaigns WHERE start_date = (
        SELECT MIN(start_date) FROM campaigns
    )
);

SELECT h.*
FROM households h
INNER JOIN notes n ON h.household_id = n.household_id;

SELECT COUNT(DISTINCT i.household_id) AS NumberOfHouseholds
FROM interactions i
WHERE i.interaction_result = 'positive';
